TriggerOraclev10g.body:
DECLARE
  v_json                     CLOB;
  exp_timestamp_conversacion NUMBER;
  perfiles_usuario           CLOB;
  active_camp                CLOB;
  name_perfil_user_wa        VARCHAR2(20);
BEGIN

--    SELECT (SELECT PERFIL_NAME_CLIENTE FROM TKR_WHATSAPP_LAST_MSG WHERE NRO_CLIENTE = :NEW.NRO_CLIENTE) INTO name_perfil_user_wa FROM DUAL;



    SELECT  (SELECT EXPIRATION_TIMESTAMP
    FROM TKR_WHATSAPP_CONVERSACIONES
    WHERE ID_CUENTA_WHATSAPP = :NEW.ID_CUENTA_WHATSAPP
    AND NRO_CLIENTE = :NEW.NRO_CLIENTE) INTO exp_timestamp_conversacion FROM DUAL;



      SELECT (SELECT JSON_ARRAYAGG(
               JSON_OBJECT(
                 'perfil'       VALUE R.DESCRIPCION_ROL,
                 'nombres'      VALUE U.NOMBRES,
                 'apellidos'    VALUE U.APELLIDOS,
                 'genero'       VALUE G.GENERO,
                 'email'        VALUE U.CORREO_ELECTRONICO,
                 'departamento' VALUE D.NOMBRE_DEPARTAMENTO,
                 'pais'         VALUE P.NOMBRE_PAIS
               ) RETURNING CLOB
             )
      FROM TKR_USUARIOS U
      LEFT JOIN TKR_ROLES_USUARIO RU ON U.ID = RU.ID_USUARIO
      LEFT JOIN TKR_ROLES R         ON RU.ID_ROL = R.ID
      LEFT JOIN TKR_CIUDADES CI     ON U.ID_CIUDAD_RESIDENCIA = CI.ID
      LEFT JOIN TKR_DEPARTAMENTOS D ON CI.ID_DEPARTAMENTO    = D.ID
      LEFT JOIN TKR_PAISES P        ON U.ID_PAIS             = P.ID
      LEFT JOIN TKR_GENEROS G       ON U.ID_GENERO           = G.ID
     WHERE U.TELEFONO = :NEW.NRO_CLIENTE) INTO perfiles_usuario FROM DUAL;

    SELECT (SELECT JSON_ARRAYAGG(
               JSON_OBJECT(
                 'account_name' VALUE JSON_VALUE(
                                    JSON_DATA,
                                    '$.accounts.name'
                                  ),
                 'nombre'       VALUE CC.NOMBRE,
                 'apellido'     VALUE CC.APELLIDO,
                 'email'        VALUE CC.EMAIL,
                 'cargo'        VALUE CC.CARGO
               ) RETURNING CLOB
             )
      FROM TKR_WHATSAPP_CONTACT_AC CC
     WHERE CC.NRO_TELEF_AC = :NEW.NRO_CLIENTE) INTO active_camp FROM DUAL;



  -- 2) Construir el JSON completo en un CLOB
  v_json := JSON_OBJECT(
    'id_msg'              VALUE :NEW.ID,
    'tipo_msg'            VALUE :NEW.TIPO_INTERACCION,
    'perfil_name_cliente' VALUE :NEW.PERFIL_NAME_CLIENTE,
    'nro_cliente'         VALUE :NEW.NRO_CLIENTE,
    'tipo_contenido'      VALUE :NEW.TIPO_MENSAJE,
    'status_msg'          VALUE :NEW.STATUS_MSG,
    'text_msg'            VALUE SUBSTRB(:NEW.TEXT_MENSAJE_RECIBIDO,1,20),
    'tipo_archivo'        VALUE :NEW.TIPO_ARCHIVO,
    'timestamp_local'     VALUE TO_CHAR(:NEW.FECHA_ENV_RECIB_LOCAL,'YYYY-MM-DD"T"HH24:MI:SS'),
    'timestamp_meta'      VALUE TO_CHAR(:NEW.TIMESTAMP_ENV_RECIB_META),
    'tipo_msg_origen'     VALUE :NEW.TIPO_ORIGEN,
    'exp_timestamp'       VALUE TO_CHAR(exp_timestamp_conversacion),
    'listas'              VALUE 'A001' ||CASE WHEN :NEW.LISTAS_VINCULADAS IS NULL THEN NULL ELSE REPLACE(REPLACE(:NEW.LISTAS_VINCULADAS,'-,',','),'-','') END,
    'perfiles_user'       VALUE perfiles_usuario FORMAT JSON,
    'active_campaign'     VALUE active_camp FORMAT JSON
    );

  -- 3) Envío por WebSocket


  IF  :OLD.TIMESTAMP_ENV_RECIB_META IS NULL AND :NEW.TIMESTAMP_ENV_RECIB_META IS NOT NULL  THEN     --AND :NEW.TIMESTAMP_META_DELV IS NULL AND :NEW.TIMESTAMP_META_READ IS NULL 
    WHATSAPP.env_msg_webSocket(:NEW.ID, v_json);  
  ELSE 
    NULL;
  END IF;

-- 4) Envio de mensajes recibidos al chatbot  

  IF :NEW.TIPO_INTERACCION = 'msg_recibido' AND :NEW.TIPO_MENSAJE = 'texto' THEN     --AND :NEW.TIMESTAMP_META_DELV IS NULL AND :NEW.TIMESTAMP_META_READ IS NULL 
    WHATSAPP.env_msg_chatbot(:NEW.ID, :NEW.NRO_CLIENTE, :NEW.TEXT_MENSAJE_RECIBIDO);  
  ELSE 
    NULL;
  END IF;

END;
